import numpy as np

def get_entanglement_pairs(n_qubits, pattern='linear'):
    """
    Get qubit pairs for entanglement layer.
    """
    pairs = []

    if pattern == 'linear':
        # Adjacent pairs: (0,1), (1,2), (2,3), ...
        for i in range(n_qubits - 1):
            pairs.append((i, i + 1))

    elif pattern == 'circular':
        # Linear plus wrap-around
        for i in range(n_qubits - 1):
            pairs.append((i, i + 1))
        pairs.append((n_qubits - 1, 0))

    elif pattern == 'all_to_all':
        # All pairs
        for i in range(n_qubits):
            for j in range(i + 1, n_qubits):
                pairs.append((i, j))

    else:
        raise ValueError(f"Unknown pattern: {pattern}")

    return pairs

# Test
print("Entanglement Patterns:")
print("=" * 40)

for n in [3, 4, 5]:
    print(f"\n{n} qubits:")
    for pattern in ['linear', 'circular', 'all_to_all']:
        pairs = get_entanglement_pairs(n, pattern)
        print(f"  {pattern:12s}: {pairs}")
        print(f"               {len(pairs)} gates")
